@startuml
class "MainActivity" as MainActivity {
  - camera
  - duration
  + showActiveMeasurement()
  + hideActiveMeasurement()
  + createMeasurement()
  + showResult()
}

class "ResultActivity" as ResultActivity {
  - Measurement
  + displayResult()
  + backToMainActivity()
  + onCreate()
}

class "Measurement" as Measurement {
  - camera
  - int[] redValues
  - int imgPerSecond
  + captureImage() : ImageFile
  + start() : void
  + analyzeImage(imageFile) : int
  + calculateResult() : int
}

class "File" as File {
}

class "ImageFile" as ImageFile {
  - File image
  + cropImage() : void
  + toValue() : float[]
}

MainActivity --> Measurement
ResultActivity --> Measurement
ImageFile <|-- File
@enduml
